    $json$[{"name": "DOLINNOV", "website": "https://www.dolinnov.com/", "description": "Dolinnov est une société de biotechnologie développant une solution thérapeutique basé sur la technologie oligonucléotides antisens pour le traitement des douleurs chroniques sévères.", "siren": "934473190"}, {"name": "WEALTHY TECHNOLOGY", "website": "https://wealthy-technology.com/", "description": "Wealthy Technology développe une IA générative dédiée à la santé, qui automatise la rédaction réglementaire et fiabilise chaque étape du développement du médicament, jusqu’à sa mise sur le marché.", "siren": "985133008"}, {"name": "CaliCO2", "website": null, "description": "CaliCO₂ développe et commercialise un procédé innovant de captage et de libération du CO₂ assisté par electrolyse utilisant des matériaux de type Hydroxydes Double Lamellaires (HDLs).", "siren": "942296781"}, {"name": "NEOCOR THERAPEUTICS", "website": "https://neocor.fr/", "description": "Neocor Therapeutics développe une thérapie génique innovante et curative visant la régénération du coeur après infarctus ou pathologies génétiques, offrant une solution unique pour prévenir l’insuffisance cardiaque.", "siren": "980496970"}, {"name": "BIOHIVE", "website": "https://www.biohive-innovations.com/", "description": "BioHive crée de petits modèles de peau humaine à partir de cellules de patients appelés organoides de peau, pour découvrir et tester de façon plus fiable et éthique les médicaments dermatologiques.", "siren": "978466126"}, {"name": "ISENTRONIQ", "website": "https://www.isentroniq.com/", "description": "Isentroniq permet l’avènement du calcul quantique grâce à une solution de câblage rendant les ordinateurs quantiques 1000 fois plus petits et moins chers.", "siren": "944119171"}, {"name": "LUMISYNC", "website": "https://lumi-sync.com/", "description": "Lumisync développe des circuits intégrés 100% photoniques qui permettent d’améliorer les performances des data centers pour l’IA tout en réduisant significativement leur consommation énergétique.", "siren": "938475142"}, {"name": "AKEN MEDICAL", "website": "https://www.akenmedical.com/", "description": "AKEN MEDICAL développe une approche théranostique innovante contre le cancer, utilisant des nanoparticules encapsulant des radionucléides, augmentant ainsi l’efficacité, la sécurité et la précision du traitement", "siren": "918983602"}, {"name": "NOMOS", "website": "https://www.nomos.bio/", "description": "Nomos transforme les digestats en engrais biosourcé, efficace et alternatif aux synthétiques. Une solution low-tech et circulaire qui aide les agriculteurs à réduire coûts de gestion et facture d’engrais.", "siren": null}, {"name": "PlasChem", "website": "https://plaschem.vn/", "description": "PlasChem invente la chimie de demain, plus verte, plus sûre, plus compétitive, en combinant la chimie plasma, la chimie en flux continu et l’intelligence artificielle.", "siren": null}, {"name": "SAXOL", "website": "https://saxol.eu/", "description": "Saxol développe de nouveaux composés neuroprotecteurs afin de prévenir l’apparition de neuropathies périphériques, un besoin médical encore insatisfait.", "siren": "937803260"}, {"name": "STARFISH BIOSCIENCE", "website": "https://www.starfishbio.com/", "description": "STARFISH Bioscience développe des biosolutions microbiologiques brevetées de nouvelle génération pour restaurer la fertilité des sols à travers la régénération de son microbiote pour une agriculture durable.", "siren": "981922453"}, {"name": "BLUESPINE", "website": "https://www.blue-spine.com/", "description": "BlueSpine conçoit et fabrique des technologies innovantes de diagnostic et de traitement de la corrosion pour prolonger la durée de vie des infrastructures", "siren": "981615396"}, {"name": "DimiCare Biotech", "website": "https://www.dimicare-biotech.com/", "description": "Dimicare développe une nouvelle classe d’antibiotiques efficaces contre les bactéries multirésistantes, avec un risque quasi nul de résistance, ouvrant la voie à une nouvelle génération d’antibiotiques.", "siren": null}, {"name": "MISUTECH", "website": "https://www.misulab.fr/", "description": "La société MISUTECH développe MISULAB, le premier logiciel de simulation des procédés d’usinage permettant de prédire la santé et la durabilité des pièces mécaniques stratégiques et de sécurité.", "siren": "983076241"}, {"name": "NOVA DATA ANALYTICS", "website": "https://novadata.io/", "description": "Nova est une plateforme d’intelligence artificielle qui aide les grandes marques à piloter leurs ventes en ligne, optimiser leurs stocks, leurs prix et leurs campagnes marketing sur tous leurs canaux.", "siren": "978950350"}, {"name": "GEOGEMS", "website": "https://www.geogems.fr/", "description": "GeoGems développe une méthode permettant d’identifier la provenance des pierres précieuses jusqu’à leur mine d’extraction, afin de promouvoir un commerce du luxe plus transparent et éthique.", "siren": "914858444"}, {"name": "LUCHROME", "website": "https://www.luchrome.com/", "description": "Luchrome fabrique un nouvel écran électronique pour les objets connectés qui a la particularité de fonctionner avec une consommation énergétique ultra basse et d’être recyclable en fin de vie.", "siren": "977523851"}, {"name": "UNVEIL", "website": null, "description": "UNVEIL est une start-up deeptech d’instrumentation au service des biotechs. Elle développe des nouvelles technologies optiques de caractérisation de biomédicament afin d’en faciliter et accélérer le développement.", "siren": "934586231"}, {"name": "XIMED", "website": "https://www.xi-med.com/", "description": "XIMED vise d’instaurer le nouveau GOLD STANDARD en mammographie grâce à sa technologie brevetée d’imagerie X par contraste de phase, offrant un diagnostic plus précis, plus fiable et moins invasif.", "siren": "984134098"}, {"name": "ZebraMed", "website": "https://zebramed.bio/", "description": "ZebraMed transforme données vivantes en décisions cliniques: criblage automatisé à grande échelle, réduction des risques, accélération concrète des thérapies pour les patients.", "siren": "988494795"}, {"name": "BLOSSOM LIFE SCIENCES", "website": null, "description": "Blossom Life Sciences développe une bio data foundry qui génère des données biologiques\nmassives via une puce propriétaire combinant microfluidique et IA permettant d’accélérer la recherche\nen biologie.", "siren": "981215718"}, {"name": "DeepPulseNeuro", "website": null, "description": "DeepPulseNeuro ouvre une nouvelle voie dans la prise en charge de l’épilepsie grâce à un monitoring cérébral endovasculaire, offrant précision, rapidité et nouvel espoir de guérison.", "siren": "992915074"}, {"name": "ENHANCE LAB", "website": "https://enhancelab.fr/", "description": "ENHANCE LAB développe des solutions d’intelligence artificielle frugales et innovantes d’amélioration d’image telles que débruitage, super-résolution et imagerie à haute dynamique.", "siren": "920854643"}, {"name": "EPYR", "website": "https://www.epyr.co/", "description": "Epyr transforme l’électricité renouvelable en chaleur haute température grâce à un stockage thermique innovant – une solution bas-carbone, compétitive et simple à déployer pour décarboner la chaleur industrielle", "siren": "938163904"}, {"name": "TELLUS AI", "website": null, "description": "Celest Science transforme la gestion des risques avec des prévisions issues d’un modèle IA explicable jusqu’à 6 mois à l’avance, pour anticiper et atténuer l’impact des extrêmes climatiques sur l’agriculture, l’assurance et la finance.", "siren": "949645600"}, {"name": "INFOCUS THERAPEUTICS SAS", "website": "https://infocustx.com/", "description": "InFocus Therapeutics exploite l’intelligence artificielle pour concevoir et développer des petites molécules ciblant l’ARN, afin de traiter le cancer et les maladies neurodégénératives.", "siren": "982886327"}, {"name": "Innovascope", "website": "https://innova-scope.com/", "description": "Telendo propose une solution holistique aux gastro-entérologues afin d’optimiser leur pratique grâce à une assistance basée sur une visualisation complète et analysée de l’organe.", "siren": null}, {"name": "TERRATIS", "website": "https://www.terratis.fr/", "description": "Terratis développe et déploie des solutions biotechnologiques innovantes, alternatives aux pesticides, pour réduire durablement la nuisance des moustiques tigres et d’insectes nuisibles en agriculture.", "siren": "983432105"}, {"name": "CURLIM", "website": "https://curlim.eu/", "description": "Curlim développe une plateforme d’encapsulation innovante destinée à améliorer l’efficacité thérapeutique de molécules bioactives pour traiter les neuropathies périphériques héréditaires et maladies rares.", "siren": "985116748"}, {"name": "MASSALIA THERAPEUTICS", "website": "https://www.massalia-tx.com/", "description": "Massalia therapeutics conçoit des traitements innovants pour les cancers agressifs et les pathologies fibrosantes, en identifiant de nouvelles cibles et en réduisant la toxicité des thérapies.", "siren": "930905773"}, {"name": "Terdepol", "website": null, "description": "Terdepol, l’industrie qui restaure la terre, développe, fabrique et commercialise un nouveau procédé respectueux de l’environnement, permettant de décontaminer sur site les terres polluées aux hydrocarbures", "siren": "990440992"}, {"name": "THEREMIA", "website": "https://theremia.health", "description": "Theremia révolutionne la médecine de précision des maladies du système nerveux central en combinant pharmacologie, neurosciences et IA pour personnaliser les traitements et optimiser essais cliniques et développement pharmaceutique.", "siren": "982570632"}, {"name": "Sitera Pharmaceuticals", "website": null, "description": "SITERA propose une innovation de rupture pour le traitement des maladies neurodégénératives à fort besoin médical, notamment la maladie rare du syndrome de Wolfram, en développant une nouvelle molécule neuroprotectrice.", "s